# :description: Valide un objet JSON contre un schéma JSON
# :input: objet, chemin vers le schéma
# :output: tuple (is_valid: bool, erreurs: list)

import json
from jsonschema import Draft7Validator
import os

def validate_object_against_schema(data, schema_path):
    if not os.path.exists(schema_path):
        return False, [{"type": "error", "message": f"Schéma introuvable : {schema_path}"}]

    with open(schema_path, "r", encoding="utf-8") as f:
        schema = json.load(f)

    validator = Draft7Validator(schema)
    errors = []

    for error in sorted(validator.iter_errors(data), key=lambda e: e.path):
        error_details = {
            "type": error.validator,
            "message": error.message,
            "schema_path": ".".join([str(p) for p in error.schema_path]),
            "invalid_value": data
        }

        # Si c’est une erreur de champ requis, on précise lequel
        if error.validator == "required":
            error_details["required_field"] = error.message.split("'")[1]

        errors.append(error_details)

    return (len(errors) == 0), errors


